INSERT INTO houses (name, description, price_per_night, photo, location, rating, rooms, guests, lat, lng) VALUES
('Горный дом в Гунибе', 'Уютный каменный дом с видом на горы и ущелье. Традиционная дагестанская архитектура с современным комфортом. Терраса с панорамным видом.', 3500, 'https://images.unsplash.com/photo-1510798831971-661eb04b3739?w=400&h=300&fit=crop&auto=format', 'Гуниб', 4.8, 3, 6, 42.3894, 46.9539),
('Вилла у моря в Избербаше', 'Просторная вилла в 100 метрах от Каспийского моря. Собственный двор, мангальная зона, парковка. Идеально для семейного отдыха.', 5000, 'https://images.unsplash.com/photo-1499793983690-e29da59ef1c2?w=400&h=300&fit=crop&auto=format', 'Избербаш', 4.6, 4, 8, 42.5647, 47.8736),
('Гостевой дом в Дербенте', 'Гостевой дом в историческом центре Дербента. Рядом крепость Нарын-Кала и старый город. Завтрак включён.', 2500, 'https://images.unsplash.com/photo-1564013799919-ab600027ffc6?w=400&h=300&fit=crop&auto=format', 'Дербент', 4.9, 2, 4, 42.0576, 48.2932),
('Эко-дом в Ахтах', 'Экологичный дом из натуральных материалов на берегу реки. Тишина, свежий воздух и невероятные пейзажи.', 2000, 'https://images.unsplash.com/photo-1449158743715-0a90ebb6d2d8?w=400&h=300&fit=crop&auto=format', 'Ахты', 4.7, 2, 4, 41.4576, 47.7322),
('Люкс-апартаменты в Махачкале', 'Современные апартаменты в центре Махачкалы. Полностью оборудованная кухня, Wi-Fi, кондиционер. Рядом рестораны и магазины.', 4000, 'https://images.unsplash.com/photo-1522708323590-d24dbb6b0267?w=400&h=300&fit=crop&auto=format', 'Махачкала', 4.5, 2, 4, 42.9849, 47.5047);
