INSERT INTO tours (name, description, duration, price, photo, route) VALUES
('Сулакский каньон', 'Захватывающая поездка к одному из самых глубоких каньонов мира. Катание на катере по бирюзовой воде, смотровые площадки и обед с видом на каньон.', '1 день', 3000, 'https://images.unsplash.com/photo-1464822759023-fed622ff2c3b?w=400&h=300&fit=crop&auto=format', ARRAY['Махачкала', 'Дубки', 'Сулакский каньон', 'Махачкала']),
('Древний Дербент', 'Путешествие в древнейший город России. Крепость Нарын-Кала, Джума-мечеть, старые кварталы магалы и берег Каспийского моря.', '1 день', 2500, 'https://images.unsplash.com/photo-1548013146-72479768bada?w=400&h=300&fit=crop&auto=format', ARRAY['Махачкала', 'Дербент', 'Нарын-Кала', 'Махачкала']),
('Горный Дагестан', 'Тур по горным аулам: Гуниб, Чох, Гамсутль — заброшенный аул-призрак. Горные перевалы, водопады и традиционная кухня.', '2 дня', 7000, 'https://images.unsplash.com/photo-1506905925346-21bda4d32df4?w=400&h=300&fit=crop&auto=format', ARRAY['Махачкала', 'Гуниб', 'Чох', 'Гамсутль', 'Махачкала']),
('Водопады и озёра', 'Маршрут по водопадам Дагестана: Тобот, Хунзахский водопад. Посещение высокогорного озера Кезеной-Ам на границе с Чечнёй.', '2 дня', 6500, 'https://images.unsplash.com/photo-1518623489648-a173ef7824f3?w=400&h=300&fit=crop&auto=format', ARRAY['Махачкала', 'Хунзах', 'Водопад Тобот', 'Кезеной-Ам', 'Махачкала']),
('Южный Дагестан', 'Тур по южному Дагестану: село Куруш — самое высокогорное в Европе, Ахтынские горячие источники, каньон реки Самур.', '3 дня', 9000, 'https://images.unsplash.com/photo-1500534314209-a25ddb2bd429?w=400&h=300&fit=crop&auto=format', ARRAY['Махачкала', 'Ахты', 'Куруш', 'Самурский лес', 'Махачкала']);
